VALUES
  ('real-estate-moex-01692', 'real-estate', 'real-estate-moex-103-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '土地所有權人出售其自用住宅用地，經使用過一生一次的土地增值稅優惠稅率後，如再出售其自用住宅 用地，仍要適用優惠稅率，應符合之條件何者正確？', '["出售都市土地面積未超過300平方公尺", "出售時土地所有權人與其配偶及未成年子女，無該自用住宅以外之房屋", "出售前一年內，無供營業使用或出租", "土地所有權人於土地出售前，在該地設有戶籍，且持有該自用住宅連續滿五年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "64b35f831206", "answer_pdf_sha1": "f925b0123c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01693', 'real-estate', 'real-estate-moex-103-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '某甲於民國102年3月1日購買房地產A，並於同年4月1日完成登記，購買房地產後因小孩在外縣市 就學，某甲夫妻及未成年子女戶籍皆未設籍於該房地產，但某甲將父親戶籍設於該房地產，若某甲僅有 房地產A，妻及未成年子女名下亦無房地產，民國103年3月5日將該房地產以1,000萬元簽約出售，持 有期間並未供營業或出租，依特種貨物及勞務稅、地價稅、房屋稅之相關課徵規定，下列何者正確？', '["某甲出售房地產A無須課徵特種貨物及勞務稅", "某甲持有房地產A期間，符合申請地價稅自用住宅稅率之條件", "某甲出售房地產A須課徵特種貨物及勞務稅，其稅率為百分之十", "某甲持有房地產A期間，不符合房屋稅住家用自用稅率"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "64b35f831206", "answer_pdf_sha1": "f925b0123c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01694', 'real-estate', 'real-estate-moex-103-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '某甲擁有A、B兩筆住宅區土地，A地當年度課徵地價稅之申報地價為5,000元/m2，面積100 m2，B地當 年度課徵地價稅之申報地價為2,000元/m2，面積200 m2，某甲將B地信託與某乙，某乙名下無任何土地， 某甲享有全部信託利益，信託10年，目前尚有3年信託期滿，若A、B兩筆土地均在同一縣市，該縣市 當年度累進起點地價為100萬元，若某甲當年度未申請A、B兩地為自用住宅用地，則某甲當年度應繳地 價稅為：', '["5,000元", "9,000元", "4,000元", "3,000元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "64b35f831206", "answer_pdf_sha1": "f925b0123c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01695', 'real-estate', 'real-estate-moex-103-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依據土地稅法及相關法律之規定，下列有關地價稅稅率之敘述何者正確？', '["工業用地按目的事業主管機關核定規劃使用者，地價稅稅率為千分之十且不累進", "經主管機關依法指定之私有古蹟及歷史建築所定著之土地，免徵地價稅", "企業或公營事業興建之勞工宿舍用地，自動工興建或取得土地所有權之日起，其用地免徵地價稅", "都市計畫公共設施保留地，在保留期間仍為建築使用，除自用住宅用地外，地價稅稅率為千分之十且 不累進"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "64b35f831206", "answer_pdf_sha1": "f925b0123c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01696', 'real-estate', 'real-estate-moex-103-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '小張在某縣市僅擁有一筆住宅區之土地，面積為400平方公尺，當年度課徵地價稅的申報地價為2,000元/m2， 土地上未有建物，小張想申請適用自用住宅優惠稅率，該縣市當年度累進起點地價為 100 萬元，小張當 年度在該縣市應繳地價稅為：', '["1,600元", "8,000元", "3,200元", "4,000元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "64b35f831206", "answer_pdf_sha1": "f925b0123c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01697', 'real-estate', 'real-estate-moex-103-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '有關徵收土地地點選擇，下列何者為非？', '["興辦公益事業應避免使用公有土地或國營事業土地", "特定農業區農牧用地，除零星夾雜難以避免者外，不得徵收", "申請徵收之土地，遇有登錄之歷史建築應於可能範圍內避免之", "興辦公益事業應儘量避免耕地"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "64b35f831206", "answer_pdf_sha1": "f925b0123c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01698', 'real-estate', 'real-estate-moex-103-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '土地所有權移轉或設定典權時，權利人、義務人、地政士、不動產經紀業申報土地移轉現值之責任，下 列何者有誤？', '["權利人及義務人應於訂定契約之日起三十日內，共同申報其土地移轉現值", "依規定得由權利人單獨申請登記者，權利人得單獨申報其移轉現值", "買賣案件委託地政士申請登記者，應由地政士申報登錄", "買賣案件委由不動產經紀業居間或代理成交，均應由不動產經紀業申報登錄"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "64b35f831206", "answer_pdf_sha1": "f925b0123c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01699', 'real-estate', 'real-estate-moex-103-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依據區域計畫法，政府依法編定之各種使用地，其土地能供使用之性質，下列何者為是？', '["甲種建築用地係供鄉村區內建築使用者", "乙種建築用地係供山坡地範圍外之農業區內建築使用者", "丙種建築用地係供森林區、山坡地保育區、風景區及山坡地範圍之農業區內建築使用者", "生態保護用地係供國土保安使用者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "64b35f831206", "answer_pdf_sha1": "f925b0123c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01700', 'real-estate', 'real-estate-moex-103-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依據土地徵收條例之規定，有關被徵收之土地、建築改良物、農作改良物之補償規定，下列敘述何者正確？', '["徵收土地應按照徵收當期之公告現值加成補償其地價", "都市計畫區內之公共設施保留地，應按毗鄰非公共設施保留地之平均市價補償其地價", "建築改良物之補償費，按起造當時該建築改良物之價格估定之", "農作改良物之補償費，於農作改良物被徵收時與其孳息成熟時期相距在一年以內者，按其種植及培育 費用，並參酌現值估定之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "64b35f831206", "answer_pdf_sha1": "f925b0123c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01701', 'real-estate', 'real-estate-moex-103-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '區段徵收土地時，有關抵價地面積及移轉時課徵土地增值稅之規定，下列何者為非？', '["抵價地總面積，以徵收總面積百分之五十為原則", "經農地重劃者，該重劃地區部分不得少於百分之四十五", "領回抵價地後第一次移轉時，以原土地所有人徵收時原有土地之地價為原地價", "區段徵收後，領回抵價地後第一次移轉時，其土地增值稅減徵百分之四十"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "64b35f831206", "answer_pdf_sha1": "f925b0123c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
